const results = [];

for (const item of items) {
  // Skip empty or invalid outputs safely
  if (!item.json.output) continue;

  let parsed;
  try {
    parsed = JSON.parse(item.json.output);
  } catch (e) {
    // If parsing fails, skip this record
    continue;
  }

  results.push({
    json: {
      postUrl: parsed.postUrl || null,
      leadName: parsed.leadName || null,
      comment: parsed.comment || null,
      intentScore: parsed.intentScore ?? null,
      intentLabel: parsed.intentLabel || null
    }
  });
}

return results;

