// ---------------------------
// COLLECT ALL POSSIBLE RESULTS
// ---------------------------
const data = items[0].json;

const results = [
  ...(data.organic_results || []),
  ...(data.inline_results || []),
  ...(data.discussions || []),
  ...(data.forums || []),
];

const problemKeywords = [
  'problem',
  'issue',
  'manual',
  'not working',
  'struggling',
  'pain',
  'challenge',
  'empty',
  'ghosted',
  'ghosting',
  'not enough',
  'low',
  'hard',
  'difficult',
  'miss',
  'failing'
];

const output = results.map(post => {
  const postUrl = post.link || '';
  let platform = 'Unknown';
  let username = null;
  let postId = null;
  let authorName = null;

  // ---------------------------
  // LINKEDIN DETECTION
  // ---------------------------
  if (/linkedin\.com\/posts\//i.test(postUrl)) {
    platform = 'LinkedIn';

    const match = postUrl.match(/linkedin\.com\/posts\/([^_]+).*?(\d{8,})/i);
    if (match) {
      username = match[1];
      postId = match[2];
    }

    authorName = post.source
      ? post.source.replace('LinkedIn · ', '').trim()
      : null;
  }

  // ---------------------------
  // REDDIT DETECTION (ROBUST)
  // ---------------------------
  if (/reddit\.com/i.test(postUrl)) {
    platform = 'Reddit';

    const redditMatch = postUrl.match(
      /reddit\.com\/r\/([^/]+)\/comments\/([^/]+)/i
    );

    if (redditMatch) {
      username = `r/${redditMatch[1]}`;
      postId = redditMatch[2];
    }

    authorName = post.source
      ? post.source.replace('Reddit · ', '').trim()
      : username;
  }

  // ---------------------------
  // PROBLEM DETECTION
  // ---------------------------
  const text = `${post.title || ''} ${post.snippet || ''}`.toLowerCase();

  const detectedProblems = problemKeywords.filter(k =>
    text.includes(k)
  );

  return {
    json: {
      platform,
      author_name: authorName,
      username,
      post_id: postId,
      post_url: postUrl || null,
      post_title: post.title || null,
      post_snippet: post.snippet || null,
      engagement_hint: post.displayed_link || null,
      problem_keywords_detected: detectedProblems,
      is_problem_post: detectedProblems.length > 0
    }
  };
});

// REMOVE EMPTY / UNKNOWN URL RESULTS
return output.filter(item => item.json.post_url);

const results = [];

for (const item of items) {
  const post = item.json;

  const postUrl = post.postUrl || '';
  const postContent = post.postDetails?.content || '';
  const activityUrn = post.postDetails?.activityUrn || null;

  const comments = post.comments || [];

  for (const comment of comments) {
    results.push({
      json: {
        // Post info
        postUrl,
        activityUrn,
        postContent,

        // Comment info
        commentId: comment.commentId,
        commentText: comment.commentText,
        commenterName: comment.authorName,
        commenterProfileUrl: comment.profileUrl || null,
        commenterUrn: comment.commenterUrn || null,

        // Metadata
        createdAt: comment.createdAt,
        likeCount: comment.likeCount,
        replyCount: comment.replyCount,
        isProfile: comment.hasProfile
      }
    });
  }
}

return results;
